export function script(input) {
  const bundle = typeof input.githubActionsBundle === 'string' ? input.githubActionsBundle : '';
  const repositoryUrl = typeof input.repositoryUrl === 'string' ? input.repositoryUrl.trim() : '';
  const authorizationNotes = typeof input.authorizationNotes === 'string' && input.authorizationNotes.trim().length > 0 ? input.authorizationNotes.trim() : null;
  const fileSummary = input.fileSummary && typeof input.fileSummary === 'object' ? input.fileSummary : {};
  const files = Array.isArray(input.files) ? input.files : [];
  const skippedFiles = Array.isArray(input.skippedFiles) ? input.skippedFiles : [];
  const severityRank = { critical: 5, high: 4, medium: 3, low: 2, info: 1, unknown: 0 };
  const rankFor = (value) => severityRank[String(value || 'unknown').toLowerCase()] || 0;
  function splitBundle(value) {
    const chunks = [];
    const marker = /^# FILE: (.+)$/gm;
    const matches = [...String(value || '').matchAll(marker)];
    if (matches.length === 0 && String(value || '').trim().length > 0) {
      return [{ path: 'github-actions-workflow.yml', content: String(value) }];
    }
    for (let index = 0; index < matches.length; index++) {
      const current = matches[index];
      const next = matches[index + 1];
      chunks.push({
        path: String(current[1] || '').trim(),
        content: String(value).slice((current.index || 0) + current[0].length, next?.index ?? String(value).length).trim()
      });
    }
    return chunks.filter((chunk) => chunk.path && chunk.content);
  }
  function evidenceLines(content, patterns) {
    const lines = String(content || '').split(/\r?\n/);
    const matches = [];
    for (let index = 0; index < lines.length; index++) {
      const line = lines[index];
      if (patterns.some((pattern) => pattern.test(line))) {
        matches.push(`L${index + 1}: ${line.trim()}`);
      }
      if (matches.length >= 4) break;
    }
    return matches;
  }
  function priorityBand(severity) {
    if (severity === 'critical') return 'immediate';
    if (severity === 'high') return 'high-review';
    if (severity === 'medium') return 'watchlist';
    return 'backlog';
  }
  const findings = [];
  function addFinding(file, ruleId, severity, title, priorityReasons, evidence, remediation) {
    findings.push({
      ruleId,
      severity,
      title,
      filePath: file.path,
      priorityBand: priorityBand(severity),
      priorityScore: rankFor(severity) * 100 + priorityReasons.length * 10 + evidence.length,
      priorityReasons,
      evidence,
      remediation
    });
  }
  for (const file of splitBundle(bundle)) {
    const content = file.content;
    const hasPullRequestTarget = /(^|\n)\s*on\s*:\s*pull_request_target\b/i.test(content) || /(^|\n)\s*pull_request_target\s*:/i.test(content);
    const hasWriteAll = /(^|\n)\s*permissions\s*:\s*write-all\b/i.test(content);
    const hasBroadWritePermission = hasWriteAll || /(^|\n)\s*(contents|pull-requests|issues|actions|deployments|packages|security-events|id-token)\s*:\s*write\b/i.test(content);
    if (hasPullRequestTarget && hasBroadWritePermission) {
      addFinding(
        file,
        'pull-request-target-write-token',
        'critical',
        'pull_request_target workflow grants write-capable token permissions',
        [
          'pull_request_target can run attacker-controlled changes with privileged token context',
          'workflow grants broad write permissions'
        ],
        evidenceLines(content, [/pull_request_target/i, /permissions\s*:/i, /write-all|:\s*write\b/i]),
        'Prefer pull_request for untrusted code paths, split privileged follow-up jobs, and reduce GITHUB_TOKEN permissions to read-only by default.'
      );
    } else if (hasPullRequestTarget) {
      addFinding(
        file,
        'pull-request-target-review',
        'high',
        'pull_request_target workflow requires manual privilege review',
        ['pull_request_target executes in the base repository security context'],
        evidenceLines(content, [/pull_request_target/i]),
        'Confirm the workflow never checks out or executes attacker-controlled pull request code before privileged steps run.'
      );
    }
    const usesMatches = [...content.matchAll(/uses\s*:\s*([^\s#]+)@([^\s#]+)/gi)];
    for (const match of usesMatches) {
      const actionName = String(match[1] || '').trim();
      const ref = String(match[2] || '').replace(/["']/g, '').trim();
      if (!actionName || actionName.startsWith('./') || actionName.startsWith('docker://')) continue;
      const isGitHubOwned = /^actions\//i.test(actionName) || /^github\//i.test(actionName);
      const isPinnedSha = /^[a-f0-9]{40}$/i.test(ref) || /^sha256:/i.test(ref);
      if (!isPinnedSha) {
        if (isGitHubOwned) {
          addFinding(
            file,
            'mutable-github-owned-action-ref',
            'low',
            'GitHub-owned Action uses a mutable version tag',
            ['GitHub-owned action is trusted but still resolves through a mutable tag', `action reference uses ${ref || 'an unpinned ref'}`],
            [`uses: ${actionName}@${ref}`],
            'Pin sensitive workflows to a full commit SHA, or document why the GitHub-owned action tag is accepted for this program.'
          );
        } else {
          const severity = /^(main|master|head|latest|develop|dev|stable)$/i.test(ref) ? 'high' : 'medium';
          addFinding(
            file,
            'unpinned-third-party-action',
            severity,
            'Third-party GitHub Action is not pinned to an immutable digest',
            ['third-party action can change without a repository code change', `action reference uses ${ref || 'an unpinned ref'}`],
            [`uses: ${actionName}@${ref}`],
            'Pin third-party actions to a full commit SHA and review update diffs before bumping the pin.'
          );
        }
      }
    }
    if (/(^|\n)\s*runs-on\s*:\s*(\[[^\]]*self-hosted[^\]]*\]|self-hosted\b)/i.test(content)) {
      addFinding(
        file,
        'self-hosted-runner',
        'high',
        'Workflow can run on a self-hosted runner',
        ['self-hosted runners can expose internal network, workspace, and cached secrets to workflow code'],
        evidenceLines(content, [/runs-on\s*:/i, /self-hosted/i]),
        'Restrict self-hosted runners to trusted branches or isolated runner groups and avoid running untrusted pull request code on them.'
      );
    }
    const hasRiskyInstaller = /\b(curl|wget)\b[^\n|]*(\|\s*(bash|sh)|\s+-O\s+|\s+-o\s+)/i.test(content);
    if (hasRiskyInstaller) {
      addFinding(
        file,
        'remote-installer-execution',
        hasPullRequestTarget ? 'high' : 'medium',
        'Workflow executes remote installer content during CI',
        ['remote installer execution expands supply-chain trust to an external network response'],
        evidenceLines(content, [/curl\b|wget\b/i, /bash|sh/i]),
        'Replace remote installer piping with pinned package versions, checksum verification, or a reviewed setup action pinned to a commit SHA.'
      );
    }
    const referencesSecrets = /secrets\.[A-Za-z0-9_]+/i.test(content);
    if (referencesSecrets && (hasPullRequestTarget || hasRiskyInstaller || hasBroadWritePermission)) {
      addFinding(
        file,
        'secret-context-in-risky-workflow',
        'high',
        'Workflow references secrets in a risky execution context',
        ['workflow references repository secrets near privileged or externally influenced execution'],
        evidenceLines(content, [/secrets\.[A-Za-z0-9_]+/i, /pull_request_target|curl\b|wget\b|permissions\s*:/i]),
        'Move secret-dependent steps behind trusted-branch checks and avoid exposing secrets to pull request influenced code paths.'
      );
    }
  }
  const priorityFindings = findings
    .sort((a, b) => b.priorityScore - a.priorityScore || String(a.filePath).localeCompare(String(b.filePath)) || a.ruleId.localeCompare(b.ruleId))
    .slice(0, 100);
  const countsBySeverity = priorityFindings.reduce((acc, finding) => {
    acc[finding.severity] = (acc[finding.severity] || 0) + 1;
    return acc;
  }, {});
  const highestSeverity = priorityFindings.reduce((current, finding) => rankFor(finding.severity) > rankFor(current) ? finding.severity : current, 'none');
  const analyticsResults = priorityFindings.map((finding) => ({
    scanner: 'github-actions-supply-chain',
    severity: finding.severity,
    finding_hash: [repositoryUrl || fileSummary.repository || 'repository', finding.filePath, finding.ruleId, finding.evidence?.[0] || finding.title].join(':'),
    asset_key: repositoryUrl || fileSummary.repository || null,
    file_path: finding.filePath,
    rule_id: finding.ruleId,
    title: finding.title,
    priority_band: finding.priorityBand
  }));
  return {
    report: {
      summary: {
        repository: repositoryUrl || fileSummary.repository || null,
        ref: fileSummary.ref || null,
        workflowFiles: Number(fileSummary.githubActionsFiles || splitBundle(bundle).length),
        selectedFiles: Number(fileSummary.selectedFiles || files.length),
        skippedFiles: skippedFiles.length || Number(fileSummary.skippedFiles || 0),
        truncated: Boolean(fileSummary.truncated),
        actionableFindings: priorityFindings.length,
        highestSeverity,
        countsBySeverity
      },
      authorizationNotes,
      extraction: {
        summary: fileSummary,
        files: files.filter((file) => file && file.category === 'github-actions').slice(0, 120),
        skippedFiles: skippedFiles.slice(0, 120)
      },
      priorityFindings,
      analyticsResults,
      nextSteps: [
        'Confirm the repository and workflow paths are in authorized bug bounty scope',
        'Manually inspect pull_request_target workflows before filing because exploitability depends on attacker-controlled checkout or script paths',
        'Pin third-party actions to full commit SHAs and reduce GITHUB_TOKEN permissions to least privilege',
        'Re-run after workflow hardening to confirm privileged CI/CD risk signals are removed'
      ]
    },
    analyticsResults
  };
}
